def main():
    with open(UNIVERSE_FILE, "r", encoding="utf-8") as f:
        data = json.load(f)

    manual = 0
    for s in data["stocks"]:
        code = s["code"]
        if code in M:
            s["deep_analysis"] = M[code]
            manual += 1
        elif s.get("deep_analysis"):
            pass  # keep existing auto
        else:
            # Smart auto-generate
            cat = s["category"]
            biz = s.get("core_business","")
            name = s["name"]
            q1r = s.get("q1_revenue")
            q1p = s.get("q1_profit")
            gm = s.get("q1_gross_margin")

            products = []
            for kw,prod in [("光模块","光模块相关产品"),("光器件","光器件产品"),("光芯片","光芯片产品"),
                           ("光纤","光纤/光缆"),("光缆","光纤/光缆"),("激光","激光器/设备"),
                           ("芯片","芯片产品"),("半导体","半导体产品"),("封测","封测服务"),
                           ("晶圆","晶圆代工"),("PCB","PCB产品"),("覆铜板","覆铜板/材料"),
                           ("服务器","服务器"),("算力","算力服务"),("数据中心","数据中心服务"),
                           ("液冷","液冷方案"),("连接器","连接器产品"),("传感器","传感器产品"),
                           ("软件","软件平台"),("AI应用","AI应用产品"),("AI","AI相关产品"),
                           ("机器人","机器人产品"),("减速器","减速器"),("伺服","伺服系统"),
                           ("安全","安全产品"),("物联网","物联网方案"),("通信","通信设备"),
                           ("设备","设备产品"),("材料","材料产品"),("元器件","元器件"),
                           ("电源","电源设备"),("云","云服务")]:
                if kw in biz:
                    products.append(P(prod,"量产","核心产品"))
                    break
            if not products:
                products = [P("主营产品","量产",biz[:40] if biz else "待确认")]

            cats_list = []
            if q1r and q1r > 0:
                ry = s.get("q1_revenue_yoy",0)
                py = s.get("q1_profit_yoy",0)
                if ry > 20: cats_list.append(f"Q1营收+{ry:.0f}%→高增长")
                if py > 20: cats_list.append(f"Q1利润+{py:.0f}%→盈利改善")
            if cat == "optical": cats_list += ["AI数据中心→光通信需求","800G/1.6T升级周期"]
            elif cat == "chip": cats_list += ["国产替代加速","AI芯片/存储需求爆发"]
            elif cat == "compute": cats_list += ["AI算力基建高速增长"]
            elif cat == "robot": cats_list += ["人形机器人产业化预期","制造业自动化升级"]
            elif cat == "app": cats_list += ["AI应用商业化落地","信创/国产替代"]
            elif cat == "infra": cats_list += ["AI数据中心扩建"]

            risks = ["行业竞争加剧","下游需求波动"]
            if cat in ("chip","optical"): risks += ["核心芯片/材料依赖进口"]
            if q1p and q1p < 0: risks.append("当前亏损→盈利拐点不确定")

            key_q = {
                "optical":"是否有自研光芯片(EML/DFB/DSP)？核心竞争壁垒是什么？",
                "chip":"制程节点/技术来源？受美国制裁影响？国产替代进度？",
                "compute":"核心芯片来源(NVIDIA/华为/自研)？液冷方案？",
                "robot":"核心零部件自研率？是否进入特斯拉/华为供应链？",
                "app":"AI收入占比？是否接入DeepSeek/OpenClaw等大模型？",
                "infra":"数据中心上架率？大客户是谁？AI算力需求占比？",
                "other":"AI相关业务实质性收入占比？核心竞争力是什么？"
            }.get(cat, "核心竞争力是什么？")

            s["deep_analysis"] = make(
                SC("上游供应商","下游客户","产业链参与者"),
                products, cats_list, risks, key_q
            )

    with open(UNIVERSE_FILE, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

    multi = sum(1 for s in data["stocks"] if len(s["deep_analysis"]["products"]) > 1)
    print(f"Manual detailed: {manual}")
    print(f"Total: {data['total']}")
    print(f"Multi-product: {multi}")

if __name__ == "__main__":
    main()
